// Split attachments from Gmail Trigger output
const items = [];
const inputData = $input.all();

// Process each input item (emails)
for (const item of inputData) {
  const json = item.json;
  const binary = item.binary || {};

  // Find all binary attachment keys (attachment_0, attachment_1, etc.)
  for (const binaryKey in binary) {
    if (binaryKey.startsWith('attachment_')) {
      const index = binaryKey.replace('attachment_', '');
      const binaryData = binary[binaryKey];

      // Extract filename and extension from binary data
      const filename = binaryData.fileName || binaryData.filename || `attachment_${index}`;
      const mimeType = binaryData.mimeType || binaryData['mimeType'] || 'application/octet-stream';

      // Extract file extension from filename
      const fileExtension = filename.includes('.') 
        ? filename.split('.').pop().toLowerCase()
        : 'unknown';

      items.push({
        json: {
          messageId: json.id || json.messageId || `msg_${Date.now()}_${index}`,
          from: json.from || 'unknown@sender.com',
          subject: json.subject || 'No Subject',
          originalFilename: filename,
          mimeType: mimeType,
          size: binaryData.fileSize || 'unknown',
          fileExtension: fileExtension,
          attachmentIndex: parseInt(index) || 0,
          attachmentKey: binaryKey,
          // Include original email data for reference
          emailHeaders: json.headers,
          emailDate: json.date
        },
        binary: {
          data: binaryData
        }
      });
    }
  }
}

// Return items or debug info if no attachments found
return items.length > 0 ? items : [{
  json: { 
    error: 'No binary attachments found',
    inputKeys: Object.keys($input.item.json),
    binaryKeys: Object.keys($input.item.binary || {}),
    sampleBinaryData: $input.item.binary.attachment_0 ? {
      fileName: $input.item.binary.attachment_0.fileName,
      mimeType: $input.item.binary.attachment_0.mimeType,
      fileSize: $input.item.binary.attachment_0.fileSize
    } : 'No attachment_0 found'
  }
}];

// Prepare content for LLM - limit and clean
let contentSummary = "";
const maxChars = 1000; // Limit for LLM context

// Safely get values with defaults
const extractedData = $json.extractedData || $json; // Sometimes data is at root level
const mimeType = $json.mimeType || "";
const originalFilename = $json.originalFilename || "unknown_file";
const fromEmail = $json.from || "unknown_sender";
const fileExtension = $json.fileExtension || "unknown";

// Check for extracted content
if (extractedData) {
  if (mimeType.includes('pdf') || extractedData.text) {
    // PDF: Extract text content
    const text = extractedData.text || "";
    if (text.trim()) {
      contentSummary = text.substring(0, maxChars).trim();
    }
  } else if (mimeType.includes('spreadsheet') || mimeType.includes('csv')) {
    // Spreadsheet/CSV: Headers + first few rows
    const rows = Array.isArray(extractedData) ? extractedData.slice(0, 3) : [];
    contentSummary = JSON.stringify(rows, null, 2).substring(0, maxChars);
  } else if (mimeType.includes('word') || mimeType.includes('document')) {
    // DOCX: First paragraphs
    const text = typeof extractedData === 'string' ? extractedData : 
                 extractedData.text || JSON.stringify(extractedData);
    contentSummary = text.substring(0, maxChars).trim();
  } else {
    // Other formats: Convert to string and limit
    const text = typeof extractedData === 'string' ? extractedData :
                 JSON.stringify(extractedData);
    contentSummary = text.substring(0, maxChars).trim();
  }
}

// Fallback to filename if no content
if (!contentSummary) {
  contentSummary = `Filename: ${originalFilename}, From: ${fromEmail}, Type: ${fileExtension.toUpperCase()}`;
}

return {
  ...$json,
  contentSummary,
  contentLength: contentSummary.length,
  extractionMethod: contentSummary.includes('Filename:') ? 'filename_only' : 'content_extracted'
};

