// Process OpenAI response and create sanitized filename
let generatedName = "unknown_document";

// Extract filename from OpenAI response
if ($json.choices && $json.choices[0] && $json.choices[0].message && $json.choices[0].message.content) {
  const response = $json.choices[0].message.content.trim();
  // Clean filename - remove problematic characters
  generatedName = response
    .replace(/[\/\\:*?"<>|]/g, '_')
    .replace(/\s+/g, '_')
    .replace(/_+/g, '_')
    .substring(0, 80); // Length limit
}

// Get original data (we need to merge this with the original attachment data)
// The OpenAI response doesn't contain the original file data, so we need to get it from the input
const originalExt = 'pdf'; // You may need to get this from the original data
const sender = 'unknown'; // You may need to get this from the original data  
const date = new Date().toISOString().split('T')[0];

// Build final filename according to template
let finalName = $parameter.FILENAME_TEMPLATE || "detected_topic__sender__yyyy-mm-dd";
finalName = finalName
  .replace('detected_topic', generatedName)
  .replace('sender', sender)
  .replace('yyyy-mm-dd', date);

// Final sanitization
finalName = finalName
  .replace(/[\/\\:*?"<>|]/g, '_')
  .replace(/\s+/g, '_')
  .replace(/_+/g, '_')
  .toLowerCase()
  .substring(0, 100) + '.' + originalExt;

return {
  generatedFilename: generatedName,
  finalFilename: finalName,
  sanitizedName: finalName,
  llmProvider: 'openai',
  usage: $json.usage || null,
  originalResponse: $json // Keep original for debugging
};

// Generate unique key for duplicate detection
